    private fun handleDeepLink(intent: Intent) {
        intent.data?.let { uri ->
            when (uri.host) {
                "profile" -> navigateToProfile(uri.pathSegments.getOrNull(1))
                "payment" -> navigateToPaymentConfirmation(uri.queryParameter("orderId"))
                else -> showInvalidUrlError()
            }
        } ?: showInvalidUrlError()
    }

    private fun navigateToProfile(userId: String?) {
        userId?.let { id ->
            // Navigate to ProfileActivity with user ID
            val intent = Intent(this, ProfileActivity::class.java)
            intent.putExtra("userId", id)
            startActivity(intent)
        } ?: showInvalidUrlError()
    }

    private fun navigateToPaymentConfirmation(orderId: String?) {
        orderId?.let { id ->
            // Navigate to PaymentConfirmationActivity with order ID
            val intent = Intent(this, PaymentConfirmationActivity::class.java)
            intent.putExtra("orderId", id)
            startActivity(intent)
        } ?: showInvalidUrlError()
    }

